        return 0, fmt.Errorf("yigin bos")
    }
    son := len(y.items) - 1
    deger := y.items[son]
    y.items = y.items[:son]
    return deger, nil
}

func (y *Yigin) BosMu() bool {
    return len(y.items) == 0
}

